beginner_examples.example:
{
  studentId: '20260001',
  name: 'Alice',
  enrollmentList: [
    { courseId: 'CS101', semester: 'Fall2024', grade: 'A' },
    { courseId: 'CS202', semester: 'Spring2024', grade: 'A-' }
  ]
}

beginner_examples.query:
db.students.aggregate([
  { $lookup: {
      from: 'enrollments',
      localField: 'studentId',
      foreignField: 'studentId',
      as: 'currentCourses'
    }
  },
  { $match: { currentCourses: { $ne: [] } } }
])

db.students.aggregate([
  { $lookup: {
      from: 'enrollments',
      localField: 'studentId',
      foreignField: 'studentId',
      as: 'enrollments'
    }
  },
  { $addFields: { hasEnrollments: { $gt: [{ $size: '$enrollments' }, 0] } } }
])

intermediate_examples.query:
db.students.aggregate([
  { $lookup: {
      from: 'enrollments',
      localField: 'studentId',
      foreignField: 'studentId',
      as: 'enrollments'
    }
  },
  { $lookup: {
      from: 'grades',
      localField: 'studentId',
      foreignField: 'studentId',
      as: 'grades'
    }
  }
])

db.students.aggregate([
  { $lookup: {
      from: 'enrollments',
      localField: 'studentId',
      foreignField: 'studentId',
      as: 'enrollments'
    }
  },
  { $unwind: '$enrollments' },
  { $lookup: {
      from: 'courses',
      localField: 'enrollments.courseId',
      foreignField: 'courseId',
      as: 'courseDetails'
    }
  },
  { $unwind: '$courseDetails' }
])

db.students.aggregate([
  { $lookup: {
      from: 'enrollments',
      let: { studentId: '$studentId', major: '$major' },
      pipeline: [
        { $match: { $expr: { $eq: ['$studentId', '$$studentId'] } } },
        { $match: { semester: 'Fall2024' } }
      ],
      as: 'fallEnrollments'
    }
  }
])

db.students.aggregate([
  { $lookup: {
      from: 'grades',
      let: { studentId: '$studentId' },
      pipeline: [
        { $match: { $expr: { $eq: ['$studentId', '$$studentId'] } } },
        { $group: { _id: null, avgGrade: { $avg: '$score' } } }
      ],
      as: 'gradeStats'
    }
  }
])

db.students.aggregate([
  { $lookup: {
      from: 'enrollments',
      let: { studentId: '$studentId' },
      pipeline: [
        { $match: { $expr: { $eq: ['$studentId', '$$studentId'] } } },
        { $sort: { enrollmentDate: -1 } },
        { $limit: 3 }
      ],
      as: 'recentEnrollments'
    }
  }
])

advanced_examples.query:
db.students.aggregate([
  { $lookup: {
      from: 'students',
      localField: 'major',
      foreignField: 'major',
      as: 'classmates'
    }
  },
  { $project: { name: 1, major: 1, classmates: { $filter: { input: '$classmates', as: 'classmate', cond: { $ne: ['$_id', '$$classmate._id'] } } } } }
])

db.students.aggregate([
  { $lookup: {
      from: 'instructors',
      localField: 'advisorId',
      foreignField: 'instructorId',
      as: 'advisor'
    }
  },
  { $lookup: {
      from: 'enrollments',
      localField: 'studentId',
      foreignField: 'studentId',
      as: 'enrollments'
    }
  },
  { $lookup: {
      from: 'courses',
      localField: 'enrollments.courseId',
      foreignField: 'courseId',
      as: 'courses'
    }
  }
])

db.students.aggregate([
  { $lookup: {
      from: 'scholarships',
      let: { studentId: '$studentId', gpa: '$gpa' },
      pipeline: [
        { $match: { $expr: { $and: [{ $eq: ['$studentId', '$$studentId'] }, { $gte: ['$$gpa', 3.5] }] } } }
      ],
      as: 'eligibleScholarships'
    }
  }
])

db.students.aggregate([
  { $match: { major: 'CS', gpa: { $gte: 3.5 } } },
  { $lookup: {
      from: 'enrollments',
      localField: 'studentId',
      foreignField: 'studentId',
      as: 'enrollments'
    }
  }
])

// Ensure foreignField is indexed
db.enrollments.createIndex({ studentId: 1 })

db.students.aggregate([...])
